#include <bits/stdc++.h>
using namespace std;
const int maxn=100005;
int z[maxn],a,b,l=1,r;
bool jj(int x) {
	int n=z[1],ans=0;
	for(int i=2; i<=a; i++) {
		while(z[i]-n<x&&i<=a) {
			ans++;
			i++;
		}
		n=z[i];
	}
	ans=a-ans;
	if(ans>=b) {
		return 1;
	}
	return 0;
}
int main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>a>>b;
	for(int i=1; i<=a; i++) {
		cin>>z[i];
	}
	sort(z+1,z+a+1);
	r=z[a]-z[1];
	while(l<r) {
		int m=(l+r+1)>>1;
		if(jj(m)) {
			l=m;
		} else {
			r=m-1;
		}
	}
	cout<<l;
	return 0;
}
